 6→import com.taskflow.dto.UserResponse;
 7→import com.taskflow.entity.User;
 8→import com.taskflow.repository.UserRepository;
 9→import com.taskflow.security.JwtTokenProvider;
10→import org.springframework.http.HttpStatus;
11→import org.springframework.security.crypto.password.PasswordEncoder;
12→import org.springframework.stereotype.Service;
13→import org.springframework.web.server.ResponseStatusException;
14→
15→@Service
16→public class AuthService {
17→
18→    private final UserRepository userRepository;
19→    private final PasswordEncoder passwordEncoder;
20→    private final JwtTokenProvider jwtTokenProvider;
21→
22→    public AuthService(UserRepository userRepository,
23→                       PasswordEncoder passwordEncoder,
24→                       JwtTokenProvider jwtTokenProvider) {
25→        this.userRepository = userRepository;
26→        this.passwordEncoder = passwordEncoder;
27→        this.jwtTokenProvider = jwtTokenProvider;
28→    }
29→
30→    public UserResponse register(RegisterRequest request) {
31→        if (userRepository.findByUsername(request.getUsername()).isPresent()) {
32→            throw new ResponseStatusException(HttpStatus.CONFLICT, "Username already exists");
33→        }
34→
35→        User user = new User();
36→        user.setUsername(request.getUsername());
37→        user.setPassword(passwordEncoder.encode(request.getPassword()));
38→        user.setDisplayName(request.getDisplayName());
39→
40→        User saved = userRepository.save(user);
41→        return new UserResponse(saved.getId(), saved.getUsername(), saved.getDisplayName());
42→    }
43→
44→    public LoginResponse login(LoginRequest request) {
45→        User user = userRepository.findByUsername(request.getUsername())
46→                .orElseThrow(() -> new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Invalid credentials"));
47→
48→        if (!passwordEncoder.matches(request.getPassword(), user.getPassword())) {
49→            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Invalid credentials");
50→        }
51→
52→        String token = jwtTokenProvider.generateToken(user.getId());
53→        return new LoginResponse(token, 86400);
54→    }
55→
56→    public UserResponse getCurrentUser(Long userId) {
57→        User user = userRepository.findById(userId)
58→                .orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "User not found"));
59→
60→        return new UserResponse(user.getId(), user.getUsername(), user.getDisplayName());
61→    }
62→}
