 10→import com.taskflow.repository.TaskRepository;
 11→import org.springframework.data.domain.Page;
 12→import org.springframework.data.domain.PageRequest;
 13→import org.springframework.data.domain.Pageable;
 14→import org.springframework.data.domain.Sort;
 15→
 16→import java.time.LocalDateTime;
 17→import java.util.List;
 18→import org.springframework.stereotype.Service;
 19→import org.springframework.transaction.annotation.Transactional;
 20→
 21→@Service
 22→public class TaskService {
 23→
 24→    private final TaskRepository taskRepository;
 25→
 26→    public TaskService(TaskRepository taskRepository) {
 27→        this.taskRepository = taskRepository;
 28→    }
 29→
 30→    @Transactional
 31→    public Task create(CreateTaskRequest request, Long userId) {
 32→        Task task = new Task();
 33→        task.setTitle(request.getTitle());
 34→        task.setDescription(request.getDescription());
 35→        task.setPriority(request.getPriority());
 36→        task.setCreatedBy(userId);
 37→        return taskRepository.save(task);
 38→    }
 39→
 40→    @Transactional(readOnly = true)
 41→    public Task getById(Long id) {
 42→        Task task = taskRepository.findById(id)
 43→                .orElseThrow(() -> new ResourceNotFoundException("Task not found with id: " + id));
 44→        if (task.isDeleted()) {
 45→            throw new ResourceNotFoundException("Task not found with id: " + id);
 46→        }
 47→        return task;
 48→    }
 49→
 50→    @Transactional
 51→    public Task update(Long id, UpdateTaskRequest request) {
 52→        Task task = getById(id);
 53→        task.setTitle(request.getTitle());
 54→        task.setDescription(request.getDescription());
 55→        if (request.getPriority() != null) {
 56→            task.setPriority(request.getPriority());
 57→        }
 58→        return taskRepository.save(task);
 59→    }
 60→
 61→    @Transactional
 62→    public void softDelete(Long id) {
 63→        Task task = getById(id);
 64→        task.setDeleted(true);
 65→        taskRepository.save(task);
 66→    }
 67→
 68→    @Transactional(readOnly = true)
 69→    public Page<Task> list(String keyword, Task.Priority priority, int page, int size) {
 70→        Pageable pageable = PageRequest.of(page, size, Sort.by(Sort.Direction.DESC, "createdAt"));
 71→
 72→        if (keyword != null && !keyword.isBlank() && priority != null) {
 73→            return taskRepository.findByDeletedFalseAndTitleContainingIgnoreCaseAndPriority(keyword, priority, pageable);
 74→        } else if (keyword != null && !keyword.isBlank()) {
 75→            return taskRepository.findByDeletedFalseAndTitleContainingIgnoreCase(keyword, pageable);
 76→        } else if (priority != null) {
 77→            return taskRepository.findByDeletedFalseAndPriority(priority, pageable);
 78→        } else {
 79→            return taskRepository.findByDeletedFalse(pageable);
 80→        }
 81→    }
 82→
 83→    @Transactional
 84→    public Task transitionStatus(Long id, TaskStatus target) {
 85→        Task task = getById(id);
 86→        if (!task.getStatus().canTransitionTo(target)) {
 87→            throw new InvalidTransitionException(
 88→                    "Cannot transition from " + task.getStatus() + " to " + target);
 89→        }
 90→        task.setStatus(target);
 91→        task.setUpdatedAt(LocalDateTime.now());
 92→        return taskRepository.save(task);
 93→    }
 94→
 95→    @Transactional(readOnly = true)
 96→    public TransitionsResponse getAvailableTransitions(Long id) {
 97→        Task task = getById(id);
 98→        List<String> transitions = task.getStatus().getAllowedTransitions().stream()
 99→                .map(TaskStatus::name)
100→                .toList();
101→        TransitionsResponse response = new TransitionsResponse();
102→        response.setCurrentStatus(task.getStatus().name());
103→        response.setAvailableTransitions(transitions);
104→        return response;
105→    }
106→}
