 24→    public TaskController(TaskService taskService) {
 25→        this.taskService = taskService;
 26→    }
 27→
 28→    @PostMapping
 29→    public ResponseEntity<TaskResponse> createTask(@Valid @RequestBody CreateTaskRequest request,
 30→                                                   Authentication authentication) {
 31→        Long userId = (Long) authentication.getPrincipal();
 32→        Task task = taskService.create(request, userId);
 33→        return ResponseEntity.status(HttpStatus.CREATED).body(toResponse(task));
 34→    }
 35→
 36→    @GetMapping("/{id}")
 37→    public ResponseEntity<TaskResponse> getTask(@PathVariable Long id) {
 38→        Task task = taskService.getById(id);
 39→        return ResponseEntity.ok(toResponse(task));
 40→    }
 41→
 42→    @PutMapping("/{id}")
 43→    public ResponseEntity<TaskResponse> updateTask(@PathVariable Long id,
 44→                                                   @Valid @RequestBody UpdateTaskRequest request) {
 45→        Task task = taskService.update(id, request);
 46→        return ResponseEntity.ok(toResponse(task));
 47→    }
 48→
 49→    @DeleteMapping("/{id}")
 50→    public ResponseEntity<Void> deleteTask(@PathVariable Long id) {
