106→        response.setId(task.getId());
107→        response.setTitle(task.getTitle());
108→        response.setDescription(task.getDescription());
109→        response.setPriority(task.getPriority());
110→        response.setStatus(task.getStatus());
111→        response.setCreatedBy(task.getCreatedBy());
112→        response.setCreatedAt(task.getCreatedAt());
113→        response.setUpdatedAt(task.getUpdatedAt());
114→        return response;
115→    }
